410→/**
411→ * Get default result file path.
412→ */
413→function getDefaultResultPath(
414→  runId: string,
415→  scenarioId: string,
416→  status: string
417→): string {
418→  return path.join(
419→    process.cwd(),
420→    'evals',
421→    'results',
422→    'scenarios',
423→    runId,
424→    `${scenarioId}-${status}.json`
425→  );
426→}
