428→/**
429→ * CLI entrypoint.
430→ * Usage: tsx evals/scripts/scenario-runner.ts <scenario-id> [options]
431→ * Options:
432→ *   --keep-resources      Skip cleanup (keep resources for debugging)
433→ *   --skip-fixtures       Skip fixture provisioning
434→ *   --skip-cleanup        Skip cleanup even on success
435→ *   --cleanup-on-failure  Force cleanup even on failure
436→ *   --target=<target>     Test target: local|flyio|mittwald (default: local)
437→ */
438→if (import.meta.url === `file://${process.argv[1]}`) {
439→  const scenarioId = process.argv[2];
440→  const keepResources = process.argv.includes('--keep-resources');
441→  const skipFixtures = process.argv.includes('--skip-fixtures');
442→  const skipCleanup = process.argv.includes('--skip-cleanup');
443→  const cleanupOnFailure = process.argv.includes('--cleanup-on-failure');
444→
445→  // Parse --target flag
446→  const targetFlag = process.argv.find(arg => arg.startsWith('--target='));
447→  const target = targetFlag ? targetFlag.split('=')[1] : undefined;
448→
449→  if (!scenarioId) {
450→    console.error(
451→      'Usage: tsx evals/scripts/scenario-runner.ts <scenario-id> [options]\n' +
452→      'Options:\n' +
453→      '  --keep-resources      Skip cleanup (keep resources for debugging)\n' +
454→      '  --skip-fixtures       Skip fixture provisioning\n' +
455→      '  --skip-cleanup        Skip cleanup even on success\n' +
456→      '  --cleanup-on-failure  Force cleanup even on failure\n' +
457→      '  --target=<target>     Test target: local|flyio|mittwald (default: local)'
458→    );
459→    process.exit(1);
460→  }
461→
462→  runScenario({
463→    scenarioId,
464→    keepResources,
465→    skipFixtures,
466→    skipCleanup,
467→    cleanupOnFailure,
468→    target,
469→  })
470→    .then((result) => {
471→      process.exit(result.status === 'success' ? 0 : 1);
472→    })
473→    .catch((error) => {
474→      console.error('Fatal error:', error);
475→      process.exit(1);
476→    });
477→}
