 427→function walkJsonFiles(rootDir: string): string[] {
 428→  const out: string[] = [];
 429→
 430→  function walk(current: string): void {
 431→    const entries = fs.readdirSync(current, { withFileTypes: true });
 432→    for (const entry of entries) {
 433→      const absolute = path.join(current, entry.name);
 434→      if (entry.isDirectory()) {
 435→        walk(absolute);
 436→        continue;
 437→      }
 438→      if (entry.isFile() && entry.name.endsWith('.json')) {
 439→        out.push(absolute);
 440→      }
 441→    }
 442→  }
 443→
 444→  walk(rootDir);
 445→  return out.sort();
 446→}
 447→
 448→function loadPromptCases(
 449→  options: RunnerOptions
 450→): { cases: PromptCase[]; invalidFiles: InvalidPromptFile[] } {
 451→  if (!fs.existsSync(options.promptDir)) {
 452→    throw new Error(`Prompt directory not found: ${options.promptDir}`);
 453→  }
 454→
 455→  const files = walkJsonFiles(options.promptDir).filter(
 456→    (filePath) => path.basename(filePath) !== 'generation-manifest.json'
 457→  );
 458→
 459→  const invalidFiles: InvalidPromptFile[] = [];
 460→  const cases: PromptCase[] = [];
 461→
 462→  for (const filePath of files) {
 463→    let parsed: any;
 464→    try {
 465→      parsed = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
 466→    } catch (error) {
 467→      invalidFiles.push({
 468→        filePath,
 469→        error: error instanceof Error ? error.message : String(error),
 470→      });
 471→      continue;
 472→    }
 473→
 474→    const prompt = parsed?.input?.prompt;
 475→    const toolName = parsed?.input?.tool_name;
 476→    if (typeof prompt !== 'string' || typeof toolName !== 'string') {
 477→      continue;
 478→    }
 479→
 480→    const domain =
 481→      typeof parsed?.metadata?.domain === 'string'
 482→        ? parsed.metadata.domain
 483→        : path.basename(path.dirname(filePath));
 484→
 485→    if (options.domains && !options.domains.has(domain)) {
 486→      continue;
 487→    }
 488→
 489→    if (options.tools && !options.tools.has(normalizeToolName(toolName))) {
 490→      continue;
 491→    }
 492→
 493→    const fileBase = path.basename(filePath, '.json');
 494→    const displayName =
 495→      typeof parsed?.input?.display_name === 'string'
 496→        ? parsed.input.display_name
 497→        : fileBase;
 498→
 499→    cases.push({
 500→      id: fileBase,
 501→      domain,
 502→      promptFile: filePath,
 503→      toolName,
 504→      displayName,
 505→      prompt,
 506→    });
 507→  }
 508→
 509→  if (options.maxTools !== undefined) {
 510→    return {
 511→      cases: cases.slice(0, options.maxTools),
 512→      invalidFiles,
 513→    };
 514→  }
 515→
 516→  return { cases, invalidFiles };
 517→}
 518→
 519→function createLineParser(onLine: (line: string) => void): {
 520→  push: (chunk: string) => void;
 521→  flush: () => void;
 522→} {
 523→  let buffer = '';
 524→
 525→  return {
 526→    push(chunk: string) {
 527→      buffer += chunk;
 528→      const lines = buffer.split(/\r?\n/);
 529→      buffer = lines.pop() ?? '';
 530→      for (const line of lines) {
 531→        if (line.length > 0) {
 532→          onLine(line);
 533→        }
 534→      }
 535→    },
 536→    flush() {
 537→      if (buffer.length > 0) {
 538→        onLine(buffer);
 539→      }
 540→      buffer = '';
 541→    },
 542→  };
 543→}
 544→
 545→function parseClaudeEvent(
 546→  parsed: any,
 547→  toolsCalled: string[],
 548→  messages: string[],
 549→  toolCallErrors: string[],
 550→  mcpServerStatus: Record<string, string>
 551→): void {
 552→  if (parsed?.type === 'system' && parsed?.subtype === 'init') {
 553→    if (Array.isArray(parsed?.mcp_servers)) {
 554→      for (const server of parsed.mcp_servers) {
 555→        if (
 556→          typeof server?.name === 'string' &&
 557→          typeof server?.status === 'string'
 558→        ) {
 559→          mcpServerStatus[server.name] = server.status;
 560→        }
 561→      }
 562→    }
 563→    return;
 564→  }
 565→
 566→  if (parsed?.type === 'assistant' && parsed?.message?.content) {
 567→    const content = parsed.message.content;
 568→    if (Array.isArray(content)) {
 569→      for (const item of content) {
 570→        if (item?.type === 'tool_use' && typeof item?.name === 'string') {
 571→          toolsCalled.push(item.name);
 572→        }
 573→        if (item?.type === 'text' && typeof item?.text === 'string') {
 574→          messages.push(item.text);
 575→        }
 576→      }
 577→    }
 578→    return;
 579→  }
 580→
 581→  if (parsed?.type === 'result' && parsed?.is_error === true) {
 582→    toolCallErrors.push(
 583→      typeof parsed?.result === 'string'
 584→        ? parsed.result
 585→        : JSON.stringify(parsed?.result ?? parsed)
 586→    );
 587→  }
 588→}
 589→
 590→function parseCodexEvent(
 591→  parsed: any,
 592→  toolsCalled: string[],
 593→  messages: string[],
 594→  toolCallErrors: string[]
 595→): void {
 596→  if (parsed?.type === 'item.started' || parsed?.type === 'item.completed') {
 597→    const item = parsed?.item;
 598→    if (!item || typeof item !== 'object') {
 599→      return;
 600→    }
 601→
 602→    if (item.type === 'mcp_tool_call') {
 603→      if (typeof item.tool === 'string') {
 604→        toolsCalled.push(item.tool);
 605→      }
 606→      if (item.error) {
 607→        toolCallErrors.push(
 608→          typeof item.error === 'string' ? item.error : JSON.stringify(item.error)
 609→        );
 610→      }
 611→      if (item.status === 'failed') {
 612→        toolCallErrors.push(
 613→          `MCP tool call failed: ${typeof item.tool === 'string' ? item.tool : 'unknown_tool'}`
 614→        );
 615→      }
 616→      return;
 617→    }
 618→
 619→    if (item.type === 'agent_message' && typeof item.text === 'string') {
 620→      messages.push(item.text);
 621→      return;
 622→    }
 623→  }
 624→
 625→  if (parsed?.type === 'error') {
 626→    toolCallErrors.push(
 627→      typeof parsed?.message === 'string'
 628→        ? parsed.message
 629→        : JSON.stringify(parsed)
 630→    );
 631→  }
 632→}
 633→
 634→function parseOpencodeEvent(
 635→  parsed: any,
 636→  toolsCalled: string[],
 637→  messages: string[],
 638→  toolCallErrors: string[]
 639→): void {
 640→  if (parsed?.type === 'tool_use' && parsed?.part?.type === 'tool') {
 641→    if (typeof parsed?.part?.tool === 'string') {
 642→      toolsCalled.push(parsed.part.tool);
 643→    }
 644→    const status = parsed?.part?.state?.status;
 645→    if (status === 'error' || status === 'failed') {
 646→      toolCallErrors.push(
 647→        `Tool ${String(parsed?.part?.tool ?? 'unknown')} failed in opencode`
 648→      );
 649→    }
 650→    return;
 651→  }
 652→
 653→  if (parsed?.type === 'text' && typeof parsed?.part?.text === 'string') {
 654→    messages.push(parsed.part.text);
 655→    return;
 656→  }
 657→
 658→  if (parsed?.type === 'error') {
 659→    toolCallErrors.push(
 660→      typeof parsed?.error?.message === 'string'
 661→        ? parsed.error.message
 662→        : JSON.stringify(parsed?.error ?? parsed)
 663→    );
 664→  }
 665→}
 666→
 667→function dedupePreserveOrder(values: string[]): string[] {
 668→  const seen = new Set<string>();
 669→  const out: string[] = [];
 670→  for (const value of values) {
 671→    if (seen.has(value)) continue;
 672→    seen.add(value);
 673→    out.push(value);
 674→  }
 675→  return out;
 676→}
