 678→function buildAgentCommand(
 679→  agent: AgentName,
 680→  prompt: string,
 681→  options: RunnerOptions
 682→): { command: string; args: string[] } {
 683→  if (agent === 'claude') {
 684→    const args = [
 685→      '--print',
 686→      prompt,
 687→      '--output-format',
 688→      'stream-json',
 689→      '--verbose',
 690→      '--allowedTools',
 691→      'mcp__mittwald__*',
 692→      '--mcp-config',
 693→      options.mcpConfigPath,
 694→      '--strict-mcp-config',
 695→    ];
 696→    if (options.claudeModel) {
 697→      args.push('--model', options.claudeModel);
 698→    }
 699→    return { command: 'claude', args };
 700→  }
 701→
 702→  if (agent === 'codex') {
 703→    const args = ['exec', '--json', prompt];
 704→    if (options.codexModel) {
 705→      args.push('--model', options.codexModel);
 706→    }
 707→
 708→    args.push(
 709→      '-c',
 710→      `mcp_servers.${options.codexMcpServerName}.url="${options.mcpUrl}"`
 711→    );
 712→    for (const serverName of CODEX_MCP_SERVERS_TO_DISABLE) {
 713→      if (serverName === options.codexMcpServerName) continue;
 714→      args.push('-c', `mcp_servers.${serverName}.enabled=false`);
 715→    }
 716→
 717→    return { command: 'codex', args };
 718→  }
 719→
 720→  const args = ['run', prompt, '--format', 'json'];
 721→  if (options.opencodeModel) {
 722→    args.push('--model', options.opencodeModel);
 723→  }
 724→  return { command: 'opencode', args };
 725→}
 726→
 727→async function executePromptWithAgent(
 728→  agent: AgentName,
 729→  prompt: string,
 730→  options: RunnerOptions
 731→): Promise<AgentExecutionResult> {
 732→  const { command, args } = buildAgentCommand(agent, prompt, options);
 733→  const started = Date.now();
 734→
 735→  return await new Promise<AgentExecutionResult>((resolve) => {
 736→    const toolsCalled: string[] = [];
 737→    const messages: string[] = [];
 738→    const toolCallErrors: string[] = [];
 739→    const mcpServerStatus: Record<string, string> = {};
 740→    let stdout = '';
 741→    let stderr = '';
 742→    let parseErrors = 0;
 743→    let timedOut = false;
 744→
 745→    const child = spawn(command, args, {
 746→      cwd: process.cwd(),
 747→      stdio: ['ignore', 'pipe', 'pipe'],
 748→      env: {
 749→        ...process.env,
 750→      },
 751→    });
 752→
 753→    const stdoutParser = createLineParser((line) => {
 754→      let parsed: any;
 755→      try {
 756→        parsed = JSON.parse(line);
 757→      } catch {
 758→        parseErrors += 1;
 759→        return;
 760→      }
 761→
 762→      if (agent === 'claude') {
 763→        parseClaudeEvent(
 764→          parsed,
 765→          toolsCalled,
 766→          messages,
 767→          toolCallErrors,
 768→          mcpServerStatus
 769→        );
 770→      } else if (agent === 'codex') {
 771→        parseCodexEvent(parsed, toolsCalled, messages, toolCallErrors);
 772→      } else {
 773→        parseOpencodeEvent(parsed, toolsCalled, messages, toolCallErrors);
 774→      }
 775→    });
 776→
 777→    child.stdout.on('data', (chunk: Buffer) => {
 778→      const text = chunk.toString();
 779→      stdout += text;
 780→      stdoutParser.push(text);
 781→    });
 782→
 783→    child.stderr.on('data', (chunk: Buffer) => {
 784→      stderr += chunk.toString();
 785→    });
 786→
 787→    const timeout = setTimeout(() => {
 788→      timedOut = true;
 789→      child.kill('SIGTERM');
 790→      setTimeout(() => {
 791→        if (!child.killed) {
 792→          child.kill('SIGKILL');
 793→        }
 794→      }, 3000);
 795→    }, options.timeoutMs);
 796→
 797→    child.on('error', (error) => {
 798→      clearTimeout(timeout);
 799→      resolve({
 800→        agent,
 801→        command,
 802→        args,
 803→        exitCode: 127,
 804→        durationMs: Date.now() - started,
 805→        timedOut: false,
 806→        stdout,
 807→        stderr: `${stderr}\n${error.message}`.trim(),
 808→        toolsCalled: dedupePreserveOrder(toolsCalled),
 809→        toolCallErrors: dedupePreserveOrder(toolCallErrors),
 810→        messages,
 811→        parseErrors,
 812→        mcpServerStatus,
 813→      });
 814→    });
 815→
 816→    child.on('close', (exitCode) => {
 817→      clearTimeout(timeout);
 818→      stdoutParser.flush();
 819→
 820→      resolve({
 821→        agent,
 822→        command,
 823→        args,
 824→        exitCode,
 825→        durationMs: Date.now() - started,
 826→        timedOut,
 827→        stdout,
 828→        stderr,
 829→        toolsCalled: dedupePreserveOrder(toolsCalled),
 830→        toolCallErrors: dedupePreserveOrder(toolCallErrors),
 831→        messages,
 832→        parseErrors,
 833→        mcpServerStatus,
 834→      });
 835→    });
 836→  });
 837→}
